export interface Token {
  symbol: string;
  name: string;
  price: number;
  entryPrice: number; // For Gain Lock-100
  volume: number;
  yield: number; // APY for Stable Anchor
  priceHistory: number[]; // For SMAs, RSI, Volatility
  volumeHistory: number[]; // For Burst Hunter
  liquidityDepth: number; // For Venue Shield
}

export enum SignalType {
  BURST_HUNTER = 'BURST_HUNTER', // Conviction
  GAIN_LOCK = 'GAIN_LOCK', // Risk Mgmt
  HYPE_PULSE_BUY = 'HYPE_PULSE_BUY', // Momentum
  HYPE_PULSE_SELL = 'HYPE_PULSE_SELL',
  STABLE_ANCHOR = 'STABLE_ANCHOR', // Capital Preservation
  VENUE_SHIELD = 'VENUE_SHIELD', // Execution
}

export interface Signal {
  id: string;
  timestamp: number;
  type: SignalType;
  tokenSymbol: string;
  message: string;
  severity: 'info' | 'success' | 'warning' | 'danger';
}

export interface MarketRegime {
  status: 'BULLISH' | 'BEARISH' | 'NEUTRAL' | 'VOLATILE';
  volatility: number;
  correlation: number;
}

export class MathUtils {
  static average(data: number[]): number {
    if (data.length === 0) return 0;
    return data.reduce((a, b) => a + b, 0) / data.length;
  }

  static sma(data: number[], period: number): number | null {
    if (data.length < period) return null;
    const slice = data.slice(-period);
    return this.average(slice);
  }

  static stdDev(data: number[]): number {
    if (data.length < 2) return 0;
    const avg = this.average(data);
    const squareDiffs = data.map(value => Math.pow(value - avg, 2));
    const avgSquareDiff = this.average(squareDiffs);
    return Math.sqrt(avgSquareDiff);
  }

  static rsi(data: number[], period: number = 14): number | null {
    if (data.length < period + 1) return null;

    // Calculate changes
    const changes: number[] = [];
    for (let i = 1; i < data.length; i++) {
      changes.push(data[i] - data[i - 1]);
    }

    // Need enough changes for the period
    if (changes.length < period) return null;

    // Use simple average for RS calculation (simplified for performance vs EMA)
    const recentChanges = changes.slice(-period);

    let gains = 0;
    let losses = 0;

    recentChanges.forEach(chg => {
      if (chg > 0) gains += chg;
      else losses += Math.abs(chg);
    });

    const avgGain = gains / period;
    const avgLoss = losses / period;

    if (avgLoss === 0) return 100;

    const rs = avgGain / avgLoss;
    return 100 - (100 / (1 + rs));
  }
}

import { Injectable, signal, computed } from '@angular/core';
import { Token, Signal, SignalType, MarketRegime } from './types';
import { MathUtils } from './math-utils';

@Injectable({
  providedIn: 'root'
})
export class TokenStateService {
  // State
  readonly tokens = signal<Token[]>([]);
  readonly marketRegime = signal<MarketRegime>({ status: 'NEUTRAL', volatility: 0, correlation: 0 });

  // Computed Signals (The Algorithms)
  readonly activeSignals = computed(() => {
    const currentTokens = this.tokens();
    let signals: Signal[] = [];

    currentTokens.forEach(token => {
      // 1. BURST HUNTER (Conviction)
      // Logic: Vol > SMA20(Vol) * 3 AND PriceChange > 2% (Simplified check against last price point)
      const smaVol20 = MathUtils.sma(token.volumeHistory, 20);
      if (smaVol20) {
        const currentVol = token.volume;
        const lastPrice = token.priceHistory[token.priceHistory.length - 2] || token.price;
        const priceChange = (token.price - lastPrice) / lastPrice;

        if (currentVol > smaVol20 * 3 && priceChange > 0.02) {
          signals.push({
            id: `burst-${token.symbol}-${Date.now()}`,
            timestamp: Date.now(),
            type: SignalType.BURST_HUNTER,
            tokenSymbol: token.symbol,
            message: `Volume Burst Detected: ${(currentVol / smaVol20).toFixed(1)}x normal volume.`,
            severity: 'success'
          });
        }
      }

      // 2. GAIN LOCK-100 (Risk Mgmt)
      // Logic: Profit > 100% AND SMA10 < SMA50
      const profitMargin = (token.price - token.entryPrice) / token.entryPrice;
      const sma10 = MathUtils.sma(token.priceHistory, 10);
      const sma50 = MathUtils.sma(token.priceHistory, 50);

      if (profitMargin > 1.0 && sma10 && sma50 && sma10 < sma50) {
         signals.push({
            id: `lock-${token.symbol}-${Date.now()}`,
            timestamp: Date.now(),
            type: SignalType.GAIN_LOCK,
            tokenSymbol: token.symbol,
            message: `Take Profit: +${(profitMargin * 100).toFixed(0)}% gain with Momentum Death Cross.`,
            severity: 'warning'
          });
      }

      // 3. HYPE PULSE (Momentum)
      // Logic: RSI > 70 (Buy/Hype) 
      const rsi = MathUtils.rsi(token.priceHistory, 14);
      if (rsi && rsi > 70) {
        signals.push({
            id: `hype-${token.symbol}-${Date.now()}`,
            timestamp: Date.now(),
            type: SignalType.HYPE_PULSE_BUY,
            tokenSymbol: token.symbol,
            message: `Overbought Hype: RSI at ${rsi.toFixed(0)}. Momentum strong.`,
            severity: 'info'
          });
      }

      // 5. STABLE ANCHOR (Capital Preservation)
      // Logic: Volatility < 5% (simulated logic check) AND Yield > 5%
      const volatility = MathUtils.stdDev(token.priceHistory.slice(-20)) / token.price; // Normalized vol
      if (volatility < 0.05 && token.yield > 5.0) {
         signals.push({
            id: `anchor-${token.symbol}-${Date.now()}`,
            timestamp: Date.now(),
            type: SignalType.STABLE_ANCHOR,
            tokenSymbol: token.symbol,
            message: `Yield Safe Haven: ${token.yield}% APY with low volatility.`,
            severity: 'success'
          });
      }

      // 6. VENUE SHIELD (Execution)
      // Logic: Simple check on liquidity depth for simulation
      if (token.liquidityDepth < 1000000) { // Less than 1M liquidity
         signals.push({
            id: `venue-${token.symbol}-${Date.now()}`,
            timestamp: Date.now(),
            type: SignalType.VENUE_SHIELD,
            tokenSymbol: token.symbol,
            message: `High Slippage Risk: Low Liquidity Depth detected.`,
            severity: 'danger'
          });
      }
    });

    return signals;
  });

  // Action: Update State
  updateTokens(newTokens: Token[]) {
    this.tokens.set(newTokens);
    this.updateRegime(newTokens);
  }

  // 4. REGIME SENTINEL (Contextual)
  // Calculates market-wide metrics
  private updateRegime(tokens: Token[]) {
    // Volatility of the entire market (avg of individual volatilities)
    const avgVol = tokens.reduce((acc, t) => {
        const vol = MathUtils.stdDev(t.priceHistory.slice(-10));
        return acc + vol;
    }, 0) / tokens.length;

    // Simplified correlation proxy: Are most moving together?
    const upMoves = tokens.filter(t => t.price > t.priceHistory[t.priceHistory.length - 2]).length;
    const correlationFactor = Math.abs((upMoves / tokens.length) - 0.5) * 2; // 0 to 1, 1 means all moving same way

    let status: MarketRegime['status'] = 'NEUTRAL';
    if (avgVol > 2.0) status = 'VOLATILE';
    else if (correlationFactor > 0.6 && upMoves > tokens.length / 2) status = 'BULLISH';
    else if (correlationFactor > 0.6 && upMoves < tokens.length / 2) status = 'BEARISH';

    this.marketRegime.set({
      status,
      volatility: avgVol,
      correlation: correlationFactor
    });
  }
}

import { Injectable, inject, OnDestroy } from '@angular/core';
import { TokenStateService } from './token-state.service';
import { Token } from './types';

@Injectable({
  providedIn: 'root'
})
export class MarketSimulatorService implements OnDestroy {
  private stateService = inject(TokenStateService);
  private intervalId: any;

  // Initial Mock Data
  private tokens: Token[] = [
    this.createToken('SOL', 'Solana', 145.50, 80.00, 7.5),
    this.createToken('JUP', 'Jupiter', 1.20, 0.50, 0),
    this.createToken('PYTH', 'Pyth Network', 0.45, 0.30, 0),
    this.createToken('BONK', 'Bonk', 0.000025, 0.000010, 0),
    this.createToken('WIF', 'dogwifhat', 3.10, 1.50, 0),
    this.createToken('USDC', 'USD Coin', 1.00, 1.00, 12.5), // Stable for Anchor
  ];

  constructor() {
    this.initHistory();
    this.startSimulation();
  }

  private createToken(symbol: string, name: string, price: number, entry: number, apy: number): Token {
    return {
      symbol,
      name,
      price,
      entryPrice: entry,
      volume: 1000000,
      yield: apy,
      priceHistory: [],
      volumeHistory: [],
      liquidityDepth: 5000000 + Math.random() * 5000000
    };
  }

  // Pre-fill history so SMAs work immediately
  private initHistory() {
    this.tokens.forEach(token => {
      let currentPrice = token.price;
      let currentVol = token.volume;

      // Generate 60 periods of history
      for (let i = 0; i < 60; i++) {
        // Random walk backwards
        const change = (Math.random() - 0.5) * 0.02;
        currentPrice = currentPrice * (1 - change);
        currentVol = currentVol * (0.8 + Math.random() * 0.4);

        token.priceHistory.unshift(currentPrice);
        token.volumeHistory.unshift(currentVol);
      }
    });
    this.stateService.updateTokens([...this.tokens]);
  }

  private startSimulation() {
    this.intervalId = setInterval(() => {
      this.updateMarket();
    }, 2000); // Update every 2 seconds
  }

  private updateMarket() {
    const updatedTokens = this.tokens.map(token => {
      // Random walk price
      const volatility = token.symbol === 'USDC' ? 0.001 : 0.015; // Stable vs Crypto
      const change = (Math.random() - 0.5) * volatility * 2;
      const newPrice = token.price * (1 + change);

      // Random volume
      // Occasional burst
      const isBurst = Math.random() > 0.95;
      const newVolume = isBurst 
        ? token.volume * (3 + Math.random()) 
        : token.volume * (0.8 + Math.random() * 0.4);

      // Randomly drop liquidity for Venue Shield testing
      const newLiquidity = Math.random() > 0.9 ? 500000 : 5000000 + Math.random() * 5000000;

      // Update history
      const newPriceHistory = [...token.priceHistory, newPrice].slice(-60); // Keep last 60
      const newVolumeHistory = [...token.volumeHistory, newVolume].slice(-60);

      return {
        ...token,
        price: newPrice,
        volume: newVolume,
        liquidityDepth: newLiquidity,
        priceHistory: newPriceHistory,
        volumeHistory: newVolumeHistory
      };
    });

    this.tokens = updatedTokens;
    this.stateService.updateTokens(updatedTokens);
  }

  ngOnDestroy() {
    if (this.intervalId) clearInterval(this.intervalId);
  }
}

import { Injectable } from '@angular/core';
import { GoogleGenAI } from "@google/genai";
import { Token, MarketRegime, Signal } from './types';

@Injectable({
  providedIn: 'root'
})
export class GeminiService {
  private ai: GoogleGenAI | null = null;
  private isAvailable = false;

  constructor() {
    const key = process.env['API_KEY'];
    if (key) {
      this.ai = new GoogleGenAI({ apiKey: key });
      this.isAvailable = true;
    } else {
      console.warn('PULSAR: API_KEY not found. AI features disabled.');
    }
  }

  async generateMarketNarrative(tokens: Token[], regime: MarketRegime, signals: Signal[]): Promise<string> {
    if (!this.isAvailable || !this.ai) {
      return "AI MODULE OFFLINE. KEY MISSING.";
    }

    // Construct a dense prompt
    const tokenSummary = tokens.map(t => 
      `${t.symbol}: $${t.price.toFixed(4)}`
    ).join(', ');

    const signalSummary = signals.slice(0, 5).map(s => 
      `[${s.type}] ${s.tokenSymbol}: ${s.message}`
    ).join('; ');

    const prompt = `
      You are PULSAR, an elite crypto trading AI. 
      Market Regime: ${regime.status} (Vol: ${regime.volatility.toFixed(2)}).
      Snapshot: ${tokenSummary}.
      Active Signals: ${signalSummary}.

      Generate a concise, 2-sentence tactical narrative. Style: Cyberpunk, Bloomberg Terminal, Institutional, Urgent.
      Do not use markdown. Just plain text.
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: prompt,
      });
      return response.text || "NO NARRATIVE GENERATED";
    } catch (e) {
      console.error('Gemini Error', e);
      return "SYSTEM ERROR: AI UNREACHABLE";
    }
  }
}

