import { Injectable, signal, computed } from '@angular/core';
import { Token, Signal, SignalType, MarketRegime } from './types';
import { MathUtils } from './math-utils';

@Injectable({
  providedIn: 'root'
})
export class TokenStateService {
  // State
  readonly tokens = signal<Token[]>([]);
  readonly marketRegime = signal<MarketRegime>({ status: 'NEUTRAL', volatility: 0, correlation: 0 });

  // Computed Signals (The Algorithms)
  readonly activeSignals = computed(() => {
    const currentTokens = this.tokens();
    let signals: Signal[] = [];

    currentTokens.forEach(token => {
      // 1. BURST HUNTER (Conviction)
      // Logic: Vol > SMA20(Vol) * 3 AND PriceChange > 2% (Simplified check against last price point)
      const smaVol20 = MathUtils.sma(token.volumeHistory, 20);
      if (smaVol20) {
        const currentVol = token.volume;
        const lastPrice = token.priceHistory[token.priceHistory.length - 2] || token.price;
        const priceChange = (token.price - lastPrice) / lastPrice;

        if (currentVol > smaVol20 * 3 && priceChange > 0.02) {
          signals.push({
            id: `burst-${token.symbol}-${Date.now()}`,
            timestamp: Date.now(),
            type: SignalType.BURST_HUNTER,
            tokenSymbol: token.symbol,
            message: `Volume Burst Detected: ${(currentVol / smaVol20).toFixed(1)}x normal volume.`,
            severity: 'success'
          });
        }
      }

      // 2. GAIN LOCK-100 (Risk Mgmt)
      // Logic: Profit > 100% AND SMA10 < SMA50
      const profitMargin = (token.price - token.entryPrice) / token.entryPrice;
      const sma10 = MathUtils.sma(token.priceHistory, 10);
      const sma50 = MathUtils.sma(token.priceHistory, 50);

      if (profitMargin > 1.0 && sma10 && sma50 && sma10 < sma50) {
         signals.push({
            id: `lock-${token.symbol}-${Date.now()}`,
            timestamp: Date.now(),
            type: SignalType.GAIN_LOCK,
            tokenSymbol: token.symbol,
            message: `Take Profit: +${(profitMargin * 100).toFixed(0)}% gain with Momentum Death Cross.`,
            severity: 'warning'
          });
      }

      // 3. HYPE PULSE (Momentum)
      // Logic: RSI > 70 (Buy/Hype) 
      const rsi = MathUtils.rsi(token.priceHistory, 14);
      if (rsi && rsi > 70) {
        signals.push({
            id: `hype-${token.symbol}-${Date.now()}`,
            timestamp: Date.now(),
            type: SignalType.HYPE_PULSE_BUY,
            tokenSymbol: token.symbol,
            message: `Overbought Hype: RSI at ${rsi.toFixed(0)}. Momentum strong.`,
            severity: 'info'
          });
      }

      // 5. STABLE ANCHOR (Capital Preservation)
      // Logic: Volatility < 5% (simulated logic check) AND Yield > 5%
      const volatility = MathUtils.stdDev(token.priceHistory.slice(-20)) / token.price; // Normalized vol
      if (volatility < 0.05 && token.yield > 5.0) {
         signals.push({
            id: `anchor-${token.symbol}-${Date.now()}`,
            timestamp: Date.now(),
            type: SignalType.STABLE_ANCHOR,
            tokenSymbol: token.symbol,
            message: `Yield Safe Haven: ${token.yield}% APY with low volatility.`,
            severity: 'success'
          });
      }

      // 6. VENUE SHIELD (Execution)
      // Logic: Simple check on liquidity depth for simulation
      if (token.liquidityDepth < 1000000) { // Less than 1M liquidity
         signals.push({
            id: `venue-${token.symbol}-${Date.now()}`,
            timestamp: Date.now(),
            type: SignalType.VENUE_SHIELD,
            tokenSymbol: token.symbol,
            message: `High Slippage Risk: Low Liquidity Depth detected.`,
            severity: 'danger'
          });
      }
    });

    return signals;
  });

  // Action: Update State
  updateTokens(newTokens: Token[]) {
    this.tokens.set(newTokens);
    this.updateRegime(newTokens);
  }

  // 4. REGIME SENTINEL (Contextual)
  // Calculates market-wide metrics
  private updateRegime(tokens: Token[]) {
    // Volatility of the entire market (avg of individual normalized volatilities)
    // Coefficient of Variation = StdDev / Mean
    const avgVol = tokens.reduce((acc, t) => {
        const history = t.priceHistory.slice(-10);
        if (history.length === 0) return acc;
        const vol = MathUtils.stdDev(history) / MathUtils.average(history);
        return acc + vol;
    }, 0) / tokens.length;

    // Simplified correlation proxy: Are most moving together?
    const upMoves = tokens.filter(t => t.price > t.priceHistory[t.priceHistory.length - 2]).length;
    const correlationFactor = Math.abs((upMoves / tokens.length) - 0.5) * 2; // 0 to 1, 1 means all moving same way

    let status: MarketRegime['status'] = 'NEUTRAL';
    // Adjusted threshold for normalized volatility (e.g. > 1.5% avg volatility is high for this timeframe)
    if (avgVol > 0.015) status = 'VOLATILE'; 
    else if (correlationFactor > 0.6 && upMoves > tokens.length / 2) status = 'BULLISH';
    else if (correlationFactor > 0.6 && upMoves < tokens.length / 2) status = 'BEARISH';

    this.marketRegime.set({
      status,
      volatility: avgVol,
      correlation: correlationFactor
    });
  }
}

import { Injectable, signal } from '@angular/core';

export type AiTone = 'STANDARD' | 'CALM';
export type WidgetId = 'INTEL' | 'MARKET' | 'SIGNALS' | null;

@Injectable({
  providedIn: 'root'
})
export class UserPrefsService {
  // Cognitive Settings
  readonly reducedMotion = signal<boolean>(false);
  readonly aiTone = signal<AiTone>('STANDARD');

  // Layout State (Focus Mode)
  readonly focusedWidget = signal<WidgetId>(null);

  toggleMotion() {
    this.reducedMotion.update(v => !v);
  }

  setTone(tone: AiTone) {
    this.aiTone.set(tone);
  }

  setFocus(widgetId: WidgetId) {
    // If clicking the already focused widget, un-focus it (toggle behavior)
    if (this.focusedWidget() === widgetId) {
      this.focusedWidget.set(null);
    } else {
      this.focusedWidget.set(widgetId);
    }
  }

  clearFocus() {
    this.focusedWidget.set(null);
  }
}

import { Injectable } from '@angular/core';
import { GoogleGenAI } from "@google/genai";
import { Token, MarketRegime, Signal } from './types';
import { AiTone } from './user-prefs.service';

@Injectable({
  providedIn: 'root'
})
export class GeminiService {
  private ai: GoogleGenAI | null = null;
  private isAvailable = false;

  constructor() {
    const key = process.env['API_KEY'];
    if (key) {
      this.ai = new GoogleGenAI({ apiKey: key });
      this.isAvailable = true;
    } else {
      console.warn('PULSAR: API_KEY not found. AI features disabled.');
    }
  }

  async generateMarketNarrative(tokens: Token[], regime: MarketRegime, signals: Signal[], tone: AiTone): Promise<string> {
    if (!this.isAvailable || !this.ai) {
      return "AI MODULE OFFLINE. KEY MISSING.";
    }

    // Construct a dense prompt
    const tokenSummary = tokens.map(t => 
      `${t.symbol}: $${t.price.toFixed(4)}`
    ).join(', ');

    const signalSummary = signals.slice(0, 5).map(s => 
      `[${s.type}] ${s.tokenSymbol}: ${s.message}`
    ).join('; ');

    let styleInstruction = "";
    if (tone === 'CALM') {
      styleInstruction = "Style: Analytical, Reassuring, Clear, Objectively Optimistic. Avoid alarmist, urgent, or 'hype' language. Focus on structural clarity.";
    } else {
      styleInstruction = "Style: Cyberpunk, Bloomberg Terminal, Institutional, Urgent. High intensity.";
    }

    const prompt = `
      You are PULSAR, a crypto market intelligence system.
      Market Regime: ${regime.status} (Vol: ${regime.volatility.toFixed(2)}).
      Snapshot: ${tokenSummary}.
      Active Signals: ${signalSummary}.

      Generate a concise, 2-sentence market narrative. 
      ${styleInstruction}
      Do not use markdown. Just plain text.
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: prompt,
      });
      return response.text || "NO NARRATIVE GENERATED";
    } catch (e) {
      console.error('Gemini Error', e);
      return "SYSTEM ERROR: AI UNREACHABLE";
    }
  }
}

